			attemptId,
			claimToken,
			executionStatus: codexResult.timedOut ? "timed_out" : codexResult.exitCode === 0 ? "completed" : "failed",
			exitCode: codexResult.exitCode,
			sandboxId: CODEX_LOCAL_SANDBOX_ID,
